theory.syntax:
SELECT columns, ROW_NUMBER() OVER (ORDER BY column DESC) AS row_num FROM table_name;
SELECT columns, RANK() OVER (PARTITION BY column1 ORDER BY column2 DESC) AS rnk FROM table_name;
SELECT columns, LAG(column) OVER (ORDER BY column) AS prev_value FROM table_name;

example.query:
-- 1. Ranking all students by marks descending
SELECT name, marks, RANK() OVER (ORDER BY marks DESC) AS rnk FROM Students;

-- 2. Comparing each student's marks to the next-lower-ranked student
SELECT name, marks, LEAD(name) OVER (ORDER BY marks DESC, name) AS next_student FROM Students;

shared_table.create_sql:
CREATE TABLE Students (
  id INTEGER PRIMARY KEY,
  name TEXT,
  city TEXT,
  marks INTEGER
);
